class Solution:
    def palindromePartition(self, s: str, k: int) -> int:
        def check(mid):
            cnt = 0
            for i in range(0, len(s), mid):
                tmp = s[i:i+mid]
                l, r = 0, len(tmp) - 1
                while l < r:
                    if tmp[l] != tmp[r]:
                        cnt += 1
                    l += 1
                    r -= 1
            return cnt

        left, right = 0, sum(ord(c) - ord('a') for c in s)
        while left <= right:
            mid = (left + right) // 2
            if mid >= k:
                right = mid - 1
            elif check(mid) <= k - 1:
                right = mid - 1
            else:
                left = mid + 1
        return left
